interceptor.afterloaddata:

							//rrequest.authorize("msg", null, null, "display", "false");
							if(typeObj instanceof AbsReportType){//当前是在加载报表数据，则判断报表是否有数据，并动态添加onload回调函数
								List lstData=(List)dataObj;//此时dataObj参数存放的就是当前报表加载出的数据列表
								StringBuffer buf=new StringBuffer();
								String info="";
								if(lstData!=null&&lstData.size()>0){
										String nameTmp;
									  AbsReportDataPojo dataObjTmp;
										for(int i=0;i<1;i++){//下面将取到的所有name列的值拼凑成name1,name2,...格式
											dataObjTmp=(AbsReportDataPojo)lstData.get(i);
											nameTmp=dataObjTmp.getColStringValue("MSG_INFO");
     										if(nameTmp==null||nameTmp.trim().equals("")) continue;
						           			buf.append(nameTmp);
						        		 }
						         		if(buf.length()>0&&buf.charAt(buf.length()-1)==',') buf.deleteCharAt(buf.length()-1);
		        						}
		        						StringBuffer paramsBuf=new StringBuffer();
			               				paramsBuf.append("{pageid:\""+rbean.getPageBean().getId()+"\"");
			              				paramsBuf.append(",reportid:\""+rbean.getId()+"\"");
				        				if(buf.length()>0)
				        				{
				        					paramsBuf.append(",message:\""+buf.toString()+"\"");
				        					paramsBuf.append("}");
				        					rrequest.getWResponse().addOnloadMethod("testDynamicOnload",paramsBuf.toString(),false);//动态添加onload回调函数
				        				}else
				        				{
				        					rrequest.authorize("msg", null, null, "display", "false");
				        				}
										//	paramsBuf.append("}");
										//rrequest.getWResponse().addOnloadMethod("testDynamicOnload",paramsBuf.toString(),false);//动态添加onload回调函数
							}
							return super.afterLoadData(rrequest,rbean,typeObj,dataObj);//如果当前不是查询报表数据，则不做处理

format.value:

Date d=new Date(); 
String current_date=DateFormat.getDateInstance().format(d);
String lm_days;
if(lm_time!=null){
	lm_days=Time.getTwoDay(current_date,DateFormat.getDateInstance().format(lm_time));
}else{
	lm_days="8";
}
String new_img="&nbsp;<img style='border:0px;' src='images/firstnew.gif'>";
if("non_favor".equals(is_favor)){
	favor="<img src=\"images/star_off.gif\" style='padding-left:5px;float:left;width:15px;height:15px;cursor: pointer;' title=\"点击收藏\" onclick=\"invokeServerAction('com.customer.personalize.FavorPage',{pageid:'"+page_id+"'},InvokeCallbackMethod_refreshHome_report1,null);\">";
}else{
	favor="<img src=\"images/star_on.gif\" style='padding-left:5px;float:left;width:15px;height:15px;cursor: pointer;' title=\"取消收藏\" onclick=\"invokeServerAction('com.customer.personalize.FavorPage',{pageid:'"+page_id+"'},InvokeCallbackMethod_refreshHome_report1,null);\">";
}
if(Long.parseLong(lm_days)<7){//最近7天上线的功能,以new图样标识
	page_name="<a style='padding-left:4px; display:block; overflow:hidden; cursor:pointer;' href='ShowReport.wx?PAGEID="+page_id+(url_param==null?"":url_param)+"'>"+page_name +new_img+"</a>";
}else{
	page_name="<a style='padding-left:4px;display: block; overflow: hidden; cursor: pointer;' href='ShowReport.wx?PAGEID="+page_id+(url_param==null?"":url_param)+"'>"+page_name +"</a>";
}


String favor="";
if("non_favor".equals(is_favor)){
	favor="<img src=\"images/star_off.gif\" style='padding-left:1px;padding-right:5px;float:left;width:15px;height:15px;cursor: pointer;' title=\"点击收藏\" onclick=\"invokeServerAction('com.customer.personalize.FavorPage',{pageid:'"+page_id+"'},InvokeCallbackMethod_refreshTitle,null);\">";
}else{
	favor="<img src=\"images/star_on.gif\" style='padding-left:1px;padding-right:5px;float:left;width:15px;height:15px;cursor: pointer;' title=\"取消收藏\" onclick=\"invokeServerAction('com.customer.personalize.FavorPage',{pageid:'"+page_id+"'},InvokeCallbackMethod_refreshTitle,null);\">";
}
title=favor+"<font style='color:#154BA0'>"+menu_name+"</font>>><font style='font-weight:bold;color:#154BA0'>"+page_name+"</font>";
